import { useState } from "react";
import { saveVitals } from "../services/api";
import { useNavigate } from "react-router-dom";

function Vitals() {
  const userId = localStorage.getItem("user_id");
  const navigate = useNavigate();

  const [glucose, setGlucose] = useState("");
  const [height, setHeight] = useState("");
  const [weight, setWeight] = useState("");
  const [systolicBP, setSystolicBP] = useState("");
  const [diastolicBP, setDiastolicBP] = useState("");
  const [heartRate, setHeartRate] = useState("");
  const [spo2, setSpo2] = useState("");
  const [temperature, setTemperature] = useState("");

  // BMI shown only for UI (backend recalculates)
  const bmi =
    height && weight
      ? (weight / ((height / 100) ** 2)).toFixed(2)
      : "";

  const handleSave = async () => {
    try {
      await saveVitals({
        user_id: userId,
        glucose,
        height,
        weight,
        systolic_bp: systolicBP,
        diastolic_bp: diastolicBP,
        heart_rate: heartRate,
        spo2,
        temperature,
      });

      alert("Vitals saved successfully");
      navigate("/consult");
    } catch (err) {
      alert("Failed to save vitals");
      console.error(err);
    }
  };

  return (
    <div>
      <h2>Enter Vitals</h2>

      <input
        placeholder="Glucose (mg/dL)"
        value={glucose}
        onChange={(e) => setGlucose(e.target.value)}
      /><br />

      <input
        placeholder="Height (cm)"
        value={height}
        onChange={(e) => setHeight(e.target.value)}
      /><br />

      <input
        placeholder="Weight (kg)"
        value={weight}
        onChange={(e) => setWeight(e.target.value)}
      /><br />

      <input
        placeholder="Systolic BP (e.g. 120)"
        value={systolicBP}
        onChange={(e) => setSystolicBP(e.target.value)}
      /><br />

      <input
        placeholder="Diastolic BP (e.g. 80)"
        value={diastolicBP}
        onChange={(e) => setDiastolicBP(e.target.value)}
      /><br />

      <input
        placeholder="Heart Rate (bpm)"
        value={heartRate}
        onChange={(e) => setHeartRate(e.target.value)}
      /><br />

      <input
        placeholder="SpO₂ (%)"
        value={spo2}
        onChange={(e) => setSpo2(e.target.value)}
      /><br />

      <input
        placeholder="Temperature (°F)"
        value={temperature}
        onChange={(e) => setTemperature(e.target.value)}
      /><br />

      <p><b>Calculated BMI:</b> {bmi}</p>

      <button onClick={handleSave}>Save Vitals</button>
    </div>
  );
}

export default Vitals;
